Add Contact to Campaign.code:
// Add an existing Contact to an existing Campaign by inserting a CampaignMember.
create('CampaignMember', {
  CampaignId: $.data.campaignId,
  ContactId:  $.data.contactId,
  Status:     'Sent',
});

Create Record.code:
// Create a record on any sObject.
create(
  // 1) API name of the sObject.
  'Account',
  // 2) Field values, or an array of objects for bulk insert.
  {
    Name: $.data.accountName,
    Industry: $.data.industry,
  }
);

Update Lead.code:
// Update an existing Lead (Id is required in the payload).
update('Lead', {
  Id: $.data.leadId,
  Status: 'Qualified',
  Email:  $.data.email,
});

Update Record.code:
// Update any sObject record. Id field is required.
update($.data.sObjectName, {
  Id: $.data.recordId,
  ...$.data.fields,
});

API Request (Beta).code:
// Make a raw, authenticated request against the Salesforce REST API.
sfRequest({
  method: 'GET',
  url: '/services/data/v59.0/limits',
});

Execute SOQL Query.code:
// Run a SOQL query.
query(
  `SELECT Id, Name, Email FROM Contact WHERE Email = '${$.data.email}' LIMIT 1`
);

Find Child Records.code:
// Find child Contacts for a given Account using SOQL.
query(
  `SELECT Id, Name FROM Contact WHERE AccountId = '${$.data.accountId}'`
);

Find Record.code:
// Find one record by a couple of fields.
query(
  `SELECT Id, Name FROM Account WHERE Name = '${$.data.name}' AND Industry = '${$.data.industry}' LIMIT 1`
);

Find Record (SOQL).code:
// Find a record using a SOQL WHERE clause you control.
query(
  `SELECT Id, Name FROM Account WHERE ${$.data.whereClause} LIMIT 1`
);

Find Records (Line Items).code:
// Find many records by a single field/value match.
query(
  `SELECT Id, Name, Email FROM Contact WHERE AccountId = '${$.data.accountId}' LIMIT 200`
);

Find Records (SOQL).code:
// Find many records using a SOQL WHERE clause you control.
query(
  `SELECT Id, Name FROM Account WHERE ${$.data.whereClause} LIMIT 200`
);

Get Notes and Attachments.code:
// Pull ContentDocumentLink rows for a record to enumerate attached files.
query(
  `SELECT ContentDocumentId, ContentDocument.Title, ContentDocument.FileType ` +
  `FROM ContentDocumentLink WHERE LinkedEntityId = '${$.data.recordId}'`
);
